SELECT b.board_no AS boardNo, b.member_id AS memberId, a.name AS adminName, m.login_id AS adminLoginId, b.type, b.title, b.view_count AS viewCount, b.block, b.savefilename AS saveFilename, b.start_date AS startDate, b.end_date AS endDate, b.created_at AS createdAt FROM board b LEFT JOIN member m ON b.member_id = m.member_id LEFT JOIN admin_detail a ON m.member_id = a.member_id
AND b.type = #{type}
AND
AND b.block = #{block}
ORDER BY b.board_no DESC OFFSET #{offset} ROWS FETCH FIRST #{size} ROWS ONLY
